let Recon = SigninLogs | where TimeGenerated > ago(7d) | where ResultType != "0" | summarize Attempts = count(), IPs = dcount(IPAddress) by UserPrincipalName | where Attempts > 10 | extend Phase = "1-Reconnaissance", Technique = "T1589 - Credential Gathering";
let InitialAccess = SigninLogs | where TimeGenerated > ago(7d) | where ResultType == "0" | where RiskLevelDuringSignIn in ("medium", "high") | summarize Attempts = count(), IPs = dcount(IPAddress) by UserPrincipalName | extend Phase = "2-Initial Access", Technique = "T1078 - Valid Accounts";
let CredAccess = SigninLogs | where TimeGenerated > ago(7d) | where ResultType == "50074" | summarize Attempts = count(), IPs = dcount(IPAddress) by UserPrincipalName | where Attempts >= 5 | extend Phase = "3-Credential Access", Technique = "T1621 - MFA Bombing";
union Recon, InitialAccess, CredAccess
| project Phase, Technique, UserPrincipalName, Attempts, IPs
| order by Phase asc, Attempts desc

let UnsignedBinds = toscalar(Event | where TimeGenerated > ago(7d) | where EventLog == "Directory Service" | where EventID == 2889 | count);
let ClearTextBinds = toscalar(Event | where TimeGenerated > ago(7d) | where EventLog == "Directory Service" | where EventID == 2887 | count);
let ExpensiveQueries = toscalar(Event | where TimeGenerated > ago(7d) | where EventLog == "Directory Service" | where EventID == 1644 | count);
let Score = 100 -
    (case(UnsignedBinds > 1000, 30, UnsignedBinds > 100, 20, UnsignedBinds > 10, 10, 0) +
    case(ClearTextBinds > 100, 30, ClearTextBinds > 10, 20, ClearTextBinds > 0, 10, 0) +
    case(ExpensiveQueries > 100, 20, ExpensiveQueries > 10, 10, 0));
print SecurityScore = Score, UnsignedBinds = UnsignedBinds, ClearTextBinds = ClearTextBinds, ExpensiveQueries = ExpensiveQueries,
    Grade = case(Score >= 90, "A", Score >= 80, "B", Score >= 70, "C", Score >= 60, "D", "F")

let EmailUsers = AlertEvidence | where TimeGenerated > ago(7d) | join kind=inner (AlertInfo | where TimeGenerated > ago(7d) | where ServiceSource has_any ("Office 365", "MDO")) on AlertId | where isnotempty(AccountUpn) | summarize EmailAlerts = dcount(AlertId) by AccountUpn;
let IdUsers = AlertEvidence | where TimeGenerated > ago(7d) | join kind=inner (AlertInfo | where TimeGenerated > ago(7d) | where ServiceSource has_any ("Azure AD", "Microsoft Entra", "MCAS")) on AlertId | where isnotempty(AccountUpn) | summarize IdAlerts = dcount(AlertId) by AccountUpn;
EmailUsers | join kind=inner IdUsers on AccountUpn
| extend TotalAlerts = EmailAlerts + IdAlerts
| order by TotalAlerts desc
